"""
Improved predictor v6 - adds missing collapse lemmas and absorbing variable detection.
"""
import json
from collections import Counter
from cheatsheet_predictor import (
    parse_equation, is_var, tree_vars, tree_vars_set,
    compute_features, get_bare_source_features, normalize_bare_law,
    check_collapse_lemma, collapse_term, check_constant_product_lemma,
    constant_product_collapse, rename_vars, has_square, term_to_str,
    leftmost_var, rightmost_var
)


def check_collapse_lemma_v6(eq):
    """Extended collapse lemma check - includes simple projections."""
    lhs, rhs = eq

    # First check if it's bare
    if is_var(lhs) and not is_var(rhs):
        bare_var = lhs
        product_side = rhs
    elif is_var(rhs) and not is_var(lhs):
        bare_var = rhs
        product_side = lhs
    else:
        return check_collapse_lemma(eq)  # fallback for non-bare

    # Normalize
    norm = normalize_bare_law(eq)
    if norm is None:
        return check_collapse_lemma(eq)

    prod = norm[1]

    # Simple projection patterns (NEW):
    # x = y * x → RIGHT PROJECTION
    if prod == ('*', 'y', 'x'):
        return 'right_proj'

    # x = x * y → LEFT PROJECTION
    if prod == ('*', 'x', 'y'):
        return 'left_proj'

    # Additional projection patterns:
    # x = (y * x) * x → check: for all x,y: x = (y*x)*x.
    # Under right proj: (y*x)*x → x. LHS x → x. ✓
    # But need to verify this actually implies right proj.
    # Skip for now - not proven.

    # Now check the original 3 patterns
    # x = x*(y*(z*(x*y))) → LEFT PROJECTION
    lp1 = ('*', 'x', ('*', 'y', ('*', 'z', ('*', 'x', 'y'))))
    # x = x*((y*z)*(z*z)) → LEFT PROJECTION
    lp2 = ('*', 'x', ('*', ('*', 'y', 'z'), ('*', 'z', 'z')))
    if prod == lp1 or prod == lp2:
        return 'left_proj'

    # x = (((y*z)*x)*z)*x → RIGHT PROJECTION
    rp1 = ('*', ('*', ('*', ('*', 'y', 'z'), 'x'), 'z'), 'x')
    if prod == rp1:
        return 'right_proj'

    return None


def check_absorbing_source(eq):
    """Check if source equation has absorbing variables (appear on one side only).
    Returns 'absorbing_left' if a LHS-only variable exists (RHS doesn't depend on some LHS var),
    'absorbing_right' if a RHS-only variable exists,
    None otherwise."""
    lhs, rhs = eq
    lhs_vars = tree_vars_set(lhs)
    rhs_vars = tree_vars_set(rhs)

    # Variables in LHS but not RHS
    lhs_only = lhs_vars - rhs_vars
    # Variables in RHS but not LHS
    rhs_only = rhs_vars - lhs_vars

    if lhs_only and not is_var(lhs) and not is_var(rhs):
        # Non-bare equation with LHS-only variables
        # This means the result of the operation doesn't depend on those variables
        return 'absorbing_left', lhs_only
    if rhs_only and not is_var(lhs) and not is_var(rhs):
        return 'absorbing_right', rhs_only

    return None, None


