    """Extended collapse lemma check with simple projections."""
    lhs, rhs = eq
    if is_var(lhs) and not is_var(rhs):
        bare_var = lhs
        product_side = rhs
    elif is_var(rhs) and not is_var(lhs):
        bare_var = rhs
        product_side = lhs
    else:
        return None

    norm = normalize_bare_law(eq)
    if norm is None:
        return None
    prod = norm[1]

    # NEW simple projections:
    if prod == ('*', 'y', 'x'):
        return 'right_proj'
    if prod == ('*', 'x', 'y'):
        return 'left_proj'

    # Original patterns:
    lp1 = ('*', 'x', ('*', 'y', ('*', 'z', ('*', 'x', 'y'))))
    lp2 = ('*', 'x', ('*', ('*', 'y', 'z'), ('*', 'z', 'z')))
    if prod == lp1 or prod == lp2:
        return 'left_proj'

    rp1 = ('*', ('*', ('*', ('*', 'y', 'z'), 'x'), 'z'), 'x')
    if prod == rp1:
        return 'right_proj'

    return None


