    # NEW simple projections:
    if prod == ('*', 'y', 'x'):
        return 'right_proj'
    if prod == ('*', 'x', 'y'):
        return 'left_proj'

    # Original patterns:
    lp1 = ('*', 'x', ('*', 'y', ('*', 'z', ('*', 'x', 'y'))))
    lp2 = ('*', 'x', ('*', ('*', 'y', 'z'), ('*', 'z', 'z')))
    if prod == lp1 or prod == lp2:
        return 'left_proj'

    rp1 = ('*', ('*', ('*', ('*', 'y', 'z'), 'x'), 'z'), 'x')
